# Category: graphql_security

import os
from ariadne import QueryType, ObjectType, make_executable_schema, graphql_sync
from ariadne.asgi import GraphQL
from ariadne.types import Extension
from starlette.applications import Starlette
from starlette.routing import Route

# --- Data Store (In-memory for simplicity) ---
users_db = {
    "user1": {
        "id": "user1",
        "username": "alice",
        "bio": "Software Engineer",
        "email": "alice@example.com",
        "phone": "111-222-3333",
        "address": "123 Alice St",
    },
    "user2": {
        "id": "user2",
        "username": "bob",
        "bio": "Data Scientist",
        "email": "bob@example.com",
        "phone": "444-555-6666",
        "address": "456 Bob Ave",
    },
}

posts_db = {
    "post1": {
        "id": "post1",
        "title": "My First Post",
        "content": "Hello world!",
        "authorId": "user1",
    },
    "post2": {
        "id": "post2",
        "title": "GraphQL is Fun",
        "content": "Learning Ariadne is great.",
        "authorId": "user2",
    },
}

# --- Schema Definition ---
type_defs = """
    type User {
        id: ID!
        username: String!
        bio: String
        email: String
        phone: String
        address: String
        posts: [Post!]!
    }

    type Post {
        id: ID!
        title: String!
        content: String
        author: User!
    }

    type Query {
        users: [User!]!
        user(id: ID!): User
        posts: [Post!]!
        post(id: ID!): Post
        me: User
    }
"""

# --- Resolvers ---

# Query Resolvers
query = QueryType()

@query.field("users")
def resolve_users(*_):
    return list(users_db.values())

@query.field("user")
def resolve_user(*_, id):
    return users_db.get(id)

@query.field("posts")
def resolve_posts(*_):
    return list(posts_db.values())

@query.field("post")
def resolve_post(*_, id):
    return posts_db.get(id)

@query.field("me")
def resolve_me(*_, info):
    # 'info.context' will contain the current_user set by the middleware
    return info.context.get("current_user")

# User Type Resolvers
user = ObjectType("User")

@user.field("posts")
def resolve_user_posts(user_obj, *_):
    return [post for post in posts_db.values() if post["authorId"] == user_obj["id"]]

# Post Type Resolvers
post = ObjectType("Post")

@post.field("author")
def resolve_post_author(post_obj, *_):
    return users_db.get(post_obj["authorId"])

# --- Authentication Middleware (as Ariadne Extension) ---

class AuthExtension(Extension):
    def request_started(self, context):
        # Simulate authentication:
        # In a real app, this would parse headers (e.g., Authorization: Bearer <token>)
        # and fetch the user from a database.
        # For this example, we'll hardcode a user.
        # Let's say a valid token would resolve to 'user1'
        auth_token = context.get("request", {}).headers.get("authorization")

        current_user = None
        if auth_token == "Bearer valid-token-for-user1":
            current_user = users_db["user1"]
        elif auth_token == "Bearer valid-token-for-user2":
            current_user = users_db["user2"]
        # else: current_user remains None (unauthenticated)

        context["current_user"] = current_user
        # print(f"AuthExtension: current_user set to {current_user['username'] if current_user else 'None'}")

# --- Schema Execution ---
schema = make_executable_schema(type_defs, query, user, post)

# --- ASGI Application Setup ---

# Create a Starlette application
app = Starlette(debug=True)

# Add the GraphQL endpoint
app.add_route(
    "/graphql",
    GraphQL(
        schema,
        debug=True,
        extensions=[AuthExtension],
        # context_value is a function that receives the Starlette request
        # and returns the context dictionary for GraphQL resolvers.
        # This is where we pass the request object to our AuthExtension.
        context_value=lambda request: {"request": request}
    )
)

